// TestCoalescingSet_BatchingBehavior tests batching works correctly when debounce>0
// Given: CoalescingSet with 100ms window
// When: Multiple rapid updates added
// Then: Callback is invoked once with all deduplicated keys after window expires
func TestCoalescingSet_BatchingBehavior(t *testing.T) {
	ctx := context.Background()
	window := 100 * time.Millisecond

	var callbackInvocations int64
	var mu sync.Mutex
	var lastBatch []string

	callback := func(keys []string) {
		atomic.AddInt64(&callbackInvocations, 1)
		mu.Lock()
		lastBatch = keys
		mu.Unlock()
	}

	cs := cache.NewCoalescingSet(ctx, window, callback)
	defer cs.Close()

	// Add multiple keys rapidly (faster than window)
	cs.Add("entity1")
	cs.Add("entity2")
	cs.Add("entity1") // Duplicate - should be deduplicated
	cs.Add("entity3")

	// Pending count should reflect deduplicated set
	pending := cs.PendingCount()
	if pending != 3 {
		t.Errorf("Expected 3 pending entities (deduplicated), got %d", pending)
	}

	// Wait for window to expire
	time.Sleep(150 * time.Millisecond)

	// Callback should have been invoked exactly once
	invocations := atomic.LoadInt64(&callbackInvocations)
	if invocations != 1 {
		t.Errorf("Expected callback to be invoked once, got %d invocations", invocations)
	}

	// Check batch contents
	mu.Lock()
	batch := lastBatch
	mu.Unlock()

	if len(batch) != 3 {
		t.Errorf("Expected batch size 3, got %d", len(batch))
	}

	// Verify deduplication worked
	seen := make(map[string]bool)
	for _, key := range batch {
		if seen[key] {
			t.Errorf("Duplicate key %q in batch - deduplication failed", key)
		}
		seen[key] = true
	}
}

